import React from 'react';
import { Dashboard } from './Dashboard';
import './styles.css';

const transactions = Array.from({ length: 500 }, (_, i) => ({
  id: i + 1,
  description: `Transaction ${i + 1} — ${['Purchase', 'Refund', 'Transfer', 'Deposit'][i % 4]}`,
  amount: Math.round((Math.random() * 1000 + 1) * 100) / 100,
  date: new Date(2024, Math.floor(Math.random() * 12), Math.floor(Math.random() * 28) + 1)
    .toISOString().split('T')[0],
}));

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif', maxWidth: '36rem' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Transaction Dashboard</h1>
      <Dashboard transactions={transactions} />
    </div>
  );
}

import React, { useState, useRef } from 'react';
import './styles.css';

interface Transaction {
  id: number;
  description: string;
  amount: number;
  date: string;
}

// Simulates expensive computation
function computeStats(txns: Transaction[]) {
  // Artificial delay simulation — in real app this would be a heavy calculation
  let total = 0;
  let max = 0;
  for (const tx of txns) {
    total += tx.amount;
    if (tx.amount > max) max = tx.amount;
  }
  return {
    total: Math.round(total * 100) / 100,
    average: Math.round((total / txns.length) * 100) / 100,
    max: Math.round(max * 100) / 100,
  };
}

interface DashboardProps {
  transactions: Transaction[];
}

export const Dashboard: React.FC<DashboardProps> = ({ transactions }) => {
  const [theme, setTheme] = useState<'light' | 'dark'>('light');
  const [search, setSearch] = useState('');
  const computeCountRef = useRef(0);

  // BUG: Recomputes on every render (theme toggle, search, etc.)
  computeCountRef.current++;
  const stats = computeStats(transactions);

  // BUG: Also recomputes on every render
  const filtered = transactions.filter(tx =>
    tx.description.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className={`dashboard dashboard--${theme}`}>
      <div className="dashboard__toolbar">
        <button
          data-testid="theme-toggle"
          className="dashboard__theme-btn"
          onClick={() => setTheme(t => (t === 'light' ? 'dark' : 'light'))}
        >
          {theme === 'light' ? '🌙' : '☀️'}
        </button>
        <input
          data-testid="search"
          className="dashboard__search"
          placeholder="Search transactions…"
          value={search}
          onChange={e => setSearch(e.target.value)}
        />
      </div>

      <div className="dashboard__stats">
        <div className="stat">
          <span className="stat__label">Total</span>
          <span data-testid="stat-total" className="stat__value">${stats.total}</span>
        </div>
        <div className="stat">
          <span className="stat__label">Average</span>
          <span data-testid="stat-average" className="stat__value">${stats.average}</span>
        </div>
        <div className="stat">
          <span className="stat__label">Max</span>
          <span data-testid="stat-max" className="stat__value">${stats.max}</span>
        </div>
        <div className="stat">
          <span className="stat__label">Computations</span>
          <span data-testid="compute-count" className="stat__value">{computeCountRef.current}</span>
        </div>
      </div>

      <div className="dashboard__list">
        {filtered.slice(0, 20).map((tx, i) => (
          <div key={tx.id} data-testid={`tx-${i}`} className="dashboard__row">
            <span>{tx.description}</span>
            <span className="dashboard__amount">${tx.amount}</span>
          </div>
        ))}
      </div>
    </div>
  );
};

.dashboard {
  padding: 1.5rem;
  border-radius: 0.5rem;
  border: 1px solid #e5e7eb;
}

.dashboard--light {
  background: white;
  color: #111827;
}

.dashboard--dark {
  background: #1f2937;
  color: #f9fafb;
  border-color: #374151;
}

.dashboard__toolbar {
  display: flex;
  gap: 0.75rem;
  margin-bottom: 1rem;
}

.dashboard__theme-btn {
  padding: 0.5rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  background: transparent;
  cursor: pointer;
  font-size: 1rem;
}

.dashboard--dark .dashboard__theme-btn {
  border-color: #4b5563;
}

.dashboard__search {
  flex: 1;
  padding: 0.5rem 0.75rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  font-size: 0.875rem;
}

.dashboard--dark .dashboard__search {
  background: #374151;
  border-color: #4b5563;
  color: #f9fafb;
}

.dashboard__stats {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 0.75rem;
  margin-bottom: 1rem;
}

.stat {
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
  padding: 0.75rem;
  border-radius: 0.375rem;
  background: #f9fafb;
}

.dashboard--dark .stat {
  background: #374151;
}

.stat__label {
  font-size: 0.6875rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: #6b7280;
}

.stat__value {
  font-size: 1rem;
  font-weight: 600;
}

.dashboard__list {
  display: flex;
  flex-direction: column;
  max-height: 20rem;
  overflow-y: auto;
}

.dashboard__row {
  display: flex;
  justify-content: space-between;
  padding: 0.5rem 0.75rem;
  font-size: 0.8125rem;
  border-bottom: 1px solid #f3f4f6;
}

.dashboard--dark .dashboard__row {
  border-bottom-color: #374151;
}

.dashboard__amount {
  font-variant-numeric: tabular-nums;
  font-weight: 500;
}

