import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import App from './App';

describe('Memoize Expensive Computation', () => {
  it('renders stats correctly', () => {
    render(<App />);
    expect(screen.getByTestId('stat-total')).toBeInTheDocument();
    expect(screen.getByTestId('stat-average')).toBeInTheDocument();
    expect(screen.getByTestId('stat-max')).toBeInTheDocument();
  });

  it('compute count starts at 1', () => {
    render(<App />);
    expect(screen.getByTestId('compute-count')).toHaveTextContent('1');
  });

  it('toggling theme does NOT increase compute count', () => {
    render(<App />);
    const countBefore = screen.getByTestId('compute-count').textContent;
    fireEvent.click(screen.getByTestId('theme-toggle'));
    expect(screen.getByTestId('compute-count')).toHaveTextContent(countBefore!);
  });

  it('typing in search does NOT increase compute count', () => {
    render(<App />);
    const countBefore = screen.getByTestId('compute-count').textContent;
    fireEvent.change(screen.getByTestId('search'), { target: { value: 'purchase' } });
    expect(screen.getByTestId('compute-count')).toHaveTextContent(countBefore!);
  });

  it('search filters transactions', () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('search'), { target: { value: 'refund' } });
    const row = screen.getByTestId('tx-0');
    expect(row.textContent?.toLowerCase()).toContain('refund');
  });

  it('theme toggle changes appearance', () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('theme-toggle'));
    expect(screen.getByTestId('theme-toggle')).toHaveTextContent('☀️');
  });

  it('renders transaction rows', () => {
    render(<App />);
    expect(screen.getByTestId('tx-0')).toBeInTheDocument();
  });
});

